    rows = (
        [{"hs300_daily_return": 0.01, "next_close_return": 0.02} for _ in range(6)]
        + [{"hs300_daily_return": -0.01, "next_close_return": -0.02} for _ in range(6)]
        + [{"hs300_daily_return": 0.001, "next_close_return": 0.005} for _ in range(6)]
    )
