def _make_rows_r61(n: int = 20, win_frac: float = 0.6) -> list[dict]:
    import random
    random.seed(42)
    rows = []
    for i in range(n):
        ret = 0.03 if i < int(n * win_frac) else -0.02
        rows.append({"next_day_return": ret})
    return rows


