    from scripts.btst_analysis_utils import compute_tail_event_filter_analysis
    extreme_vals = [-0.20, -0.19, -0.18, -0.17, -0.16, -0.15, 0.30, 0.31, 0.32, 0.33, 0.34, 0.35]
    rows = [{"next_day_return": v} for v in extreme_vals]
