    rows = []
    for i in range(30):
        ret = -0.05 if i >= 20 else 0.05  # top loses, bot wins
        rows.append({"rs_sector_rank": float(i), "next_day_return": ret})
    result = compute_relative_strength_ranking(rows)
    assert result["rs_rank_grade"] == "D"


